#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int count = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                if ((A[i] | A[j]) <= (A[i] > A[j] ? A[i] : A[j])) {
                    count++;
                }
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

